1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for an empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should let a live cell with 2 or 3 neighbors survive", () => {
15	    // Gen 0: ### (horizontal triple / blinker)
16	    // The center cell (1,0) has exactly 2 live neighbors → it SURVIVES.
17	    // The end cells (0,0) and (2,0) each have only 1 live neighbor → they DIE.
18	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
19	    expect(result).toContainEqual([1, 0]); // center survives (2 neighbors)
20	    expect(result).not.toContainEqual([0, 0]); // end cell dies (1 neighbor)
21	  });
22	  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
23	  it.todo("should bring a dead cell with exactly 3 neighbors to life (reproduction)");
24	  it.todo("should keep a block still life unchanged");
25	  it.todo("should oscillate a blinker from vertical to horizontal");
26	});
27

1	export type Cell = [number, number]; // [x, y]
2	
3	export const nextGeneration = (cells: Cell[]): Cell[] => {
4	  const key = (x: number, y: number): string => `${x},${y}`;
5	  const live = new Set(cells.map(([x, y]) => key(x, y)));
6	
7	  const neighborCounts = new Map<string, number>();
8	  for (const [x, y] of cells) {
9	    for (let dx = -1; dx <= 1; dx++) {
10	      for (let dy = -1; dy <= 1; dy++) {
11	        if (dx === 0 && dy === 0) continue;
12	        const k = key(x + dx, y + dy);
13	        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
14	      }
15	    }
16	  }
17	
18	  const result: Cell[] = [];
19	  for (const [k, count] of neighborCounts) {
20	    const [x, y] = k.split(",").map(Number);
21	    const isAlive = live.has(k);
22	    if ((isAlive && (count === 2 || count === 3)) || (!isAlive && count >= 3)) {
23	      result.push([x, y]);
24	    }
25	  }
26	  return result;
27	};
